// Pull competitor list + FPDS award data from data lake
var sql1 = 'SELECT id, name, size_standard, threat_level, total_obligated, naics_codes, target_agencies FROM gda_competitor_watchlist ORDER BY total_obligated DESC NULLS LAST LIMIT 35';
var sql2 = "SELECT source_id, raw_data->>'awardee' as winner, raw_data->>'agency' as agency, raw_data->>'ceiling_value' as ceiling, raw_data->>'naics_code' as naics, raw_data->>'set_aside' as set_aside FROM gda_data_lake WHERE record_type = 'contract_award' ORDER BY (raw_data->>'ceiling_value')::numeric DESC";
return [{ json: { command: 'docker exec n8n-envision-postgres-1 psql -U n8n -d n8n -t -A -F\'|\' -c "' + sql1 + ';" -c "' + sql2 + ';"' } }];

var raw = $input.first().json.content || '';
var prompt = 'You are analyzing GDA competitor intelligence. Given this competitor watchlist and recent FPDS award data, identify:
1. Which watchlist competitors appear in recent awards (cross-reference)
2. New competitors NOT on the watchlist who are winning in GDA NAICS codes
3. Pricing trends by NAICS/agency
4. Teaming opportunities (SB winners who might team with GDA)

DATA:
' + raw.substring(0, 6000) + '

Return JSON: {"cross_references": [{"competitor":"name","awards_found":N,"total_value":N,"primary_agencies":[]}], "new_threats": [{"name":"name","wins":N,"value":N,"naics":"","threat_level":"high|medium|low"}], "pricing_trends": [{"naics":"code","avg_ceiling":N,"range":[min,max]}], "teaming_targets": [{"name":"name","reason":""}], "summary":"2-3 sentences"}
ONLY valid JSON.';
return [{ json: { model: 'claude-sonnet-4-20250514', max_tokens: 3000, messages: [{ role: 'user', content: prompt }] } }];
